import{getSupabase,isSupabaseConfigured}from '../supabase.js';import{api}from '../api.js';import{createMovieCard}from '../components/movieCard.js';import{applyUserTheme,buildTMDBImageURL,formatDate,initPageTransition,showToast,THEME_COLORS}from '../utils.js';import '../components/navbar.js';let supabase=null;class PublicProfileController{constructor(){this.profileUser=null;}async init(){initPageTransition();supabase=await getSupabase();const params=new URLSearchParams(window.location.search);const username=params.get('u')?.trim().toLowerCase();if(!username||!isSupabaseConfigured){this.showError();return;}try{const{data:profile,error}=await supabase .from('profiles').select('*').eq('username',username).maybeSingle();if(error||!profile){this.showError();return;}this.profileUser=profile;if(profile.theme_color){applyUserTheme(profile.theme_color);}this.renderProfile();await this.loadStatsAndContent();}catch(err){console.error('[Publico]Error al iniciar perfil público:',err);this.showError();}}showError(){document.getElementById('public-loader').style.display='none';document.getElementById('public-error').style.display='block';}renderProfile(){document.getElementById('public-loader').style.display='none';document.getElementById('public-profile-content').style.display='block';const profile=this.profileUser;const name=profile.display_name||profile.username;document.title=`${name}en CineVerse`;const avatar=profile.avatar_url||`https://api.dicebear.com/7.x/bottts/svg?seed=${encodeURIComponent(name)}`;const avatarEl=document.getElementById('public-avatar');if(avatarEl){avatarEl.src=avatar;if(profile.is_premium&&profile.avatar_frame&&profile.avatar_frame!=='none'){avatarEl.classList.add(`avatar-frame-${profile.avatar_frame}`);}}const nameEl=document.getElementById('public-name');if(nameEl)nameEl.textContent=name;const usernameEl=document.getElementById('public-username');if(usernameEl)usernameEl.textContent=`@${profile.username}`;const bioEl=document.getElementById('public-bio');if(bioEl)bioEl.textContent=profile.bio||'Sin descripción en su biografía.';const bannerBg=document.getElementById('public-banner');if(bannerBg){if(profile.is_premium&&profile.banner_url){bannerBg.style.backgroundImage=`url('${profile.banner_url}')`;bannerBg.style.backgroundSize='cover';bannerBg.style.backgroundPosition='center';}else{bannerBg.style.backgroundImage='linear-gradient(135deg,var(--accent-dark-red)0%,var(--bg-primary)80%)';}}const premiumBadge=document.getElementById('public-premium-badge');if(premiumBadge&&profile.is_premium){premiumBadge.style.display='inline-flex';}const shareBtn=document.getElementById('btn-share-profile');if(shareBtn){shareBtn.addEventListener('click',()=>{navigator.clipboard.writeText(window.location.href).then(()=>{showToast('✓ ¡Enlace de perfil copiado al portapapeles!','success');});});}}async loadStatsAndContent(){const uid=this.profileUser.id;try{const[favsRes,historyRes,reviewsRes]=await Promise.all([supabase.from('favorites').select('*').eq('user_id',uid),supabase.from('watch_history').select('*').eq('user_id',uid).order('watched_at',{ascending:false}),supabase.from('reviews').select('*').eq('user_id',uid),]);const favsList=favsRes.data||[];const historyList=historyRes.data||[];const reviewsList=reviewsRes.data||[];document.getElementById('stat-favs').textContent=favsList.length;document.getElementById('stat-vistos').textContent=historyList.length;document.getElementById('stat-reviews').textContent=reviewsList.length;this.renderGrid('public-favorites-grid',favsList.slice(0,6),'Aún no tiene favoritos agregados.');this.renderGrid('public-history-grid',historyList.slice(0,6),'No ha visto películas o series recientemente.');if(this.profileUser.pinned_review_id){const pinnedId=this.profileUser.pinned_review_id;const pinnedReview=reviewsList.find(r=>r.id.toString()===pinnedId.toString());if(pinnedReview){this.renderPinnedReview(pinnedReview);}}}catch(err){console.error('[Publico]Error al cargar contenido público:',err);}}renderGrid(elementId,list,emptyText){const grid=document.getElementById(elementId);if(!grid)return;grid.innerHTML='';if(list.length===0){grid.innerHTML=`<div style="grid-column:1/-1;text-align:center;padding:2rem;color:var(--text-muted);">${emptyText}</div>`;return;}list.forEach(item=>{const cardItem={id:item.tmdb_id,media_type:item.media_type,title:item.title,name:item.title,poster_path:item.poster_path,vote_average:item.vote_average,release_date:item.release_date};grid.appendChild(createMovieCard(cardItem,{size:'md',showType:true}));});}async renderPinnedReview(review){const container=document.getElementById('pinned-review-container');const box=document.getElementById('public-section-pinned');if(!container||!box)return;try{box.style.display='block';const details=review.media_type==='movie'?await api.getMovieDetails(review.tmdb_id):await api.getTVDetails(review.tmdb_id);const poster=buildTMDBImageURL(details?.poster_path,'w185');container.innerHTML=`<div style="display:grid;grid-template-columns:80px 1fr;gap:1.5rem;background:rgba(255,255,255,0.01);border:1px solid var(--border-subtle);padding:1.5rem;border-radius:var(--radius-md);"><img src="${poster}" alt="${review.title}" style="width:100%;aspect-ratio:2/3;object-fit:cover;border-radius:var(--radius-sm);"><div><div class="flex flex--align-center flex--justify-between" style="margin-bottom:0.5rem;"><div><h4 style="font-size:1.15rem;font-weight:700;">${review.title}</h4><span style="font-size:0.75rem;color:var(--text-secondary);text-transform:uppercase;">${review.media_type==='movie'?'Película':'Serie'}</span></div>${review.rating?`<span class="badge badge--yellow">Valoración:${review.rating}/10</span>`:''}</div><p style="font-family:var(--font-body);font-size:1.05rem;color:var(--text-secondary);line-height:1.5;white-space:pre-line;">${review.content}</p></div></div>`;}catch(e){box.style.display='none';}}}const controller=new PublicProfileController();document.addEventListener('DOMContentLoaded',()=>controller.init());export default controller;